import{_ as e,o as r,c as a,ao as l}from"./chunks/framework.BOTctrRk.js";const s="/PureFFT.jl/dev/assets/comparison.Dp6K5jhy.png",i="/PureFFT.jl/dev/assets/comparison_nonpow2.Bo6cA1jj.png",p=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md","lastUpdated":null}'),d={name:"benchmarks.md"};function o(n,t,g,h,c,y){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="Benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#Benchmarks" aria-label="Permalink to &quot;Benchmarks {#Benchmarks}&quot;">​</a></h1><p>All benchmarks: AMD Zen 5 (znver5, AVX-512), single-thread, in-place, planning excluded. Input: <code>Vector{ComplexF64}</code>, power-of-two sizes. FFTW at <code>MEASURE</code> flag. RustFFT with <code>IgnoreArrayChecks</code>. PureFFT <code>:fast</code> (autotuned).</p><h2 id="GFLOP/s-comparison" tabindex="-1">GFLOP/s comparison <a class="header-anchor" href="#GFLOP/s-comparison" aria-label="Permalink to &quot;GFLOP/s comparison {#GFLOP/s-comparison}&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><p>Flop model: <code>5 · N · log2(N)</code> (standard radix-2 count).</p><h2 id="PureFFT-:fast-vs-FFTW-and-RustFFT-GFLOP/s,-power-of-two" tabindex="-1">PureFFT <code>:fast</code> vs FFTW and RustFFT (GFLOP/s, power-of-two) <a class="header-anchor" href="#PureFFT-:fast-vs-FFTW-and-RustFFT-GFLOP/s,-power-of-two" aria-label="Permalink to &quot;PureFFT `:fast` vs FFTW and RustFFT (GFLOP/s, power-of-two) {#PureFFT-:fast-vs-FFTW-and-RustFFT-GFLOP/s,-power-of-two}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">n</th><th style="text-align:right;">FFTW</th><th style="text-align:right;">RustFFT</th><th style="text-align:right;"><strong>PureFFT <code>:fast</code></strong></th><th style="text-align:right;">verdict</th></tr></thead><tbody><tr><td style="text-align:right;">128</td><td style="text-align:right;">32</td><td style="text-align:right;">34</td><td style="text-align:right;"><strong>41</strong></td><td style="text-align:right;">PureFFT fastest</td></tr><tr><td style="text-align:right;">256</td><td style="text-align:right;">39</td><td style="text-align:right;">41</td><td style="text-align:right;"><strong>44</strong></td><td style="text-align:right;">PureFFT fastest</td></tr><tr><td style="text-align:right;">512</td><td style="text-align:right;">45</td><td style="text-align:right;">46</td><td style="text-align:right;">42</td><td style="text-align:right;">RustFFT ahead</td></tr><tr><td style="text-align:right;">1024</td><td style="text-align:right;">48</td><td style="text-align:right;">44</td><td style="text-align:right;"><strong>48</strong></td><td style="text-align:right;">parity</td></tr><tr><td style="text-align:right;">4096</td><td style="text-align:right;">46</td><td style="text-align:right;">45</td><td style="text-align:right;">44</td><td style="text-align:right;">parity</td></tr><tr><td style="text-align:right;">16384</td><td style="text-align:right;">38</td><td style="text-align:right;">41</td><td style="text-align:right;"><strong>44</strong></td><td style="text-align:right;">PureFFT fastest</td></tr><tr><td style="text-align:right;">65536</td><td style="text-align:right;">35</td><td style="text-align:right;">36</td><td style="text-align:right;"><strong>39</strong></td><td style="text-align:right;">PureFFT fastest</td></tr><tr><td style="text-align:right;">262144</td><td style="text-align:right;">27</td><td style="text-align:right;">27</td><td style="text-align:right;">26</td><td style="text-align:right;">parity (memory-bound)</td></tr></tbody></table><p>PureFFT <code>:fast</code> <strong>matches or beats both FFTW and RustFFT across most of the range</strong>. It trails only at n=64 (RustFFT&#39;s hand-tuned small butterfly) and n=512/2048 (a shuffle-bound size-32 base codelet). The small-n fused register kernels (n≤128), radix-16 pass fusion, and vectorized transpose closed the earlier gap (pure Julia was once ~0.55× of FFTW — see git history / REPORT.md).</p><h2 id="Non-power-of-two" tabindex="-1">Non-power-of-two <a class="header-anchor" href="#Non-power-of-two" aria-label="Permalink to &quot;Non-power-of-two {#Non-power-of-two}&quot;">​</a></h2><p>No O(n²) cliff: a large prime factor no longer falls to a direct DFT. PureFFT&#39;s <code>:fast</code> routes by size/factorization: small smooth → dynamically-generated mixed-radix codelet (Stage 9); smooth composite up to ~4096 → SIMD four-step with batched codelets (Stage 10, split autotuned at plan time); everything else (large prime, <strong>or smooth composite &gt; 4096</strong>) → Bluestein chirp-Z (Stage 8).</p><p>The plot sweeps smooth-composite sizes (the common non-pow2 case). PureFFT (green) reaches ~9–22 GF/s on the four-step path (≈0.6× FFTW — not yet parity, the AoS↔SoA + transpose overhead), then <strong>drops to ~5 above n≈4096</strong>: the four-step factors cap at 64 (64×64=4096), so larger smooth sizes currently fall back to Bluestein. Lifting that needs a recursive four-step (tracked as future work).</p><p><img src="'+i+'" alt=""></p><table tabindex="0"><thead><tr><th style="text-align:right;">regime</th><th style="text-align:right;">example n</th><th style="text-align:right;">PureFFT</th><th style="text-align:right;">note</th></tr></thead><tbody><tr><td style="text-align:right;">smooth, small — codelet</td><td style="text-align:right;">27 / 48</td><td style="text-align:right;"><strong>12.8</strong> / 13</td><td style="text-align:right;">beats FFTW (10.7); was ~0.2 via old mixed-radix</td></tr><tr><td style="text-align:right;">smooth composite ≤4096 — four-step</td><td style="text-align:right;">720 / 2880</td><td style="text-align:right;"><strong>22 / 22</strong></td><td style="text-align:right;">~0.6× FFTW, 2–4× Bluestein (Stage 10)</td></tr><tr><td style="text-align:right;">smooth composite &gt;4096 — Bluestein</td><td style="text-align:right;">5760 / 23040</td><td style="text-align:right;">~5</td><td style="text-align:right;">four-step ceiling; recursive four-step is future work</td></tr><tr><td style="text-align:right;">large prime / prime power — Bluestein</td><td style="text-align:right;">181 / 5793</td><td style="text-align:right;">~5</td><td style="text-align:right;">O(n log n), no cliff</td></tr></tbody></table><h2 id="All-variant-progression" tabindex="-1">All variant progression <a class="header-anchor" href="#All-variant-progression" aria-label="Permalink to &quot;All variant progression {#All-variant-progression}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Variant</th><th style="text-align:right;">GFLOP/s (F64)</th><th style="text-align:right;">Key technique</th></tr></thead><tbody><tr><td style="text-align:right;"><code>:scalar</code></td><td style="text-align:right;">7–9</td><td style="text-align:right;">Radix-2 baseline</td></tr><tr><td style="text-align:right;"><code>:base</code></td><td style="text-align:right;">11–17</td><td style="text-align:right;"><code>@simd ivdep</code> cross-pass</td></tr><tr><td style="text-align:right;"><code>:recursive</code></td><td style="text-align:right;">13–24</td><td style="text-align:right;"><code>@generated</code> codelets, cache-oblivious</td></tr><tr><td style="text-align:right;"><code>:soa</code></td><td style="text-align:right;">13–21</td><td style="text-align:right;">Split re/im (negative — split/merge overhead)</td></tr><tr><td style="text-align:right;"><code>:fourstep</code></td><td style="text-align:right;">16–22</td><td style="text-align:right;">Cache-blocked four-step</td></tr><tr><td style="text-align:right;"><code>:radix4</code></td><td style="text-align:right;">27–28</td><td style="text-align:right;">Port of rustfft Radix4 + cache-blocked transpose</td></tr><tr><td style="text-align:right;"><code>:radix4avx</code> / <code>:fast</code> (pow2)</td><td style="text-align:right;"><strong>40–48</strong></td><td style="text-align:right;">+ AVX Butterfly16/32, radix-16 fusion, small-n register kernels, vectorized transpose</td></tr><tr><td style="text-align:right;"><code>:bluestein</code></td><td style="text-align:right;">non-pow2</td><td style="text-align:right;">chirp-Z, O(n log n) on primes</td></tr><tr><td style="text-align:right;"><code>:codelet</code></td><td style="text-align:right;">non-pow2</td><td style="text-align:right;">dynamically-generated mixed-radix kernel (small smooth)</td></tr><tr><td style="text-align:right;">four-step (via <code>:fast</code>)</td><td style="text-align:right;"><strong>12–20</strong></td><td style="text-align:right;">batched SoA codelets, smooth composite non-pow2</td></tr><tr><td style="text-align:right;">FFTW-MEASURE</td><td style="text-align:right;">35–48</td><td style="text-align:right;">Reference</td></tr><tr><td style="text-align:right;">rustfft-AVX</td><td style="text-align:right;">34–46</td><td style="text-align:right;">Reference</td></tr></tbody></table><h2 id="Controlled-Julia-vs-Rust-same-algorithm" tabindex="-1">Controlled Julia vs Rust (same algorithm) <a class="header-anchor" href="#Controlled-Julia-vs-Rust-same-algorithm" aria-label="Permalink to &quot;Controlled Julia vs Rust (same algorithm) {#Controlled-Julia-vs-Rust-same-algorithm}&quot;">​</a></h2><p>To separate <strong>language</strong> from <strong>algorithm</strong>, we ran the identical radix-2 DIT kernel in both Julia and Rust (same layout, same twiddle indexing, same <code>muladd</code>/<code>mul_add</code> FMA, same <code>@inbounds</code> / <code>get_unchecked</code>). Checksums match bit-for-bit.</p><table tabindex="0"><thead><tr><th style="text-align:right;">n</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Rust</th><th style="text-align:right;">winner</th></tr></thead><tbody><tr><td style="text-align:right;">64</td><td style="text-align:right;">267 ns</td><td style="text-align:right;">240 ns</td><td style="text-align:right;">Rust +11%</td></tr><tr><td style="text-align:right;">256</td><td style="text-align:right;">1211 ns</td><td style="text-align:right;">1111 ns</td><td style="text-align:right;">Rust +9%</td></tr><tr><td style="text-align:right;">1024</td><td style="text-align:right;">5266 ns</td><td style="text-align:right;">5346 ns</td><td style="text-align:right;">tie</td></tr><tr><td style="text-align:right;">4096</td><td style="text-align:right;">24309 ns</td><td style="text-align:right;">26598 ns</td><td style="text-align:right;">Julia +9%</td></tr><tr><td style="text-align:right;">16384</td><td style="text-align:right;">143956 ns</td><td style="text-align:right;">237816 ns</td><td style="text-align:right;">Julia +65%</td></tr><tr><td style="text-align:right;">65536</td><td style="text-align:right;">1.10 ms</td><td style="text-align:right;">1.32 ms</td><td style="text-align:right;">Julia +20%</td></tr><tr><td style="text-align:right;">262144</td><td style="text-align:right;">6.83 ms</td><td style="text-align:right;">7.39 ms</td><td style="text-align:right;">Julia +8%</td></tr></tbody></table><p><strong>Conclusion: same algorithm ⇒ same speed. The language is not the lever.</strong></p><p>The earlier &quot;PureFFT is 2× slower than rustfft&quot; result was about algorithm choice, not language. Once we ported the same algorithm (rustfft&#39;s <code>Radix4</code>) to Julia, added AVX codelets, fused passes, and added register-resident small-n kernels, PureFFT reached parity and now leads at most sizes.</p><h2 id="Methodology" tabindex="-1">Methodology <a class="header-anchor" href="#Methodology" aria-label="Permalink to &quot;Methodology {#Methodology}&quot;">​</a></h2><ul><li><p><strong>Timing</strong>: BenchmarkTools <code>@belapsed</code> with <code>setup=(y=copy(x)) evals=1</code>, min over ≥400 samples.</p></li><li><p><strong>In-place</strong>: all transforms applied in-place on a fresh copy per sample.</p></li><li><p><strong>Planning excluded</strong>: plans built once outside the timing loop.</p></li><li><p><strong>Single-threaded</strong>: <code>FFTW.set_num_threads(1)</code>; RustFFT and PureFFT are single-thread by design.</p></li><li><p><strong>Correctness</strong>: all variants validated against FFTW, relative error ≤ 5e-16.</p></li></ul>',22)])])}const u=e(d,[["render",o]]);export{p as __pageData,u as default};
